package exec

import (
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"os"
	osexec "os/exec"
	"path/filepath"
	"regexp"
	"sort"
	"strconv"
	"strings"
	"sync/atomic"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
)

var errNotExecArtifact = errors.New("not an exec artifact")

const (
	execDefinitionCollection = "exec-definitions"
	execRunCollection        = "exec-runs"
	execRunAttachmentDir     = "exec-runs.d"
)

type Store struct {
	WorkingDir           string
	ExecDir              string
	DefinitionsDir       string
	RunsDir              string
	DefinitionCollection *bead.Store
	RunCollection        *bead.Store
	AgentRunner          AgentRunner
	runCounter           uint64
	graphBuilderFunc     func(string) (*docgraph.Graph, error)
}

func (s *Store) buildGraph() (*docgraph.Graph, error) {
	if s.graphBuilderFunc != nil {
		return s.graphBuilderFunc(s.WorkingDir)
	}
	return docgraph.BuildGraph(s.WorkingDir)
}

func NewStore(workingDir string) *Store {
	base := filepath.Join(workingDir, ".ddx", "exec")
	beadRoot := filepath.Join(workingDir, ".ddx")
	return &Store{
		WorkingDir:           workingDir,
		ExecDir:              base,
		DefinitionsDir:       filepath.Join(base, "definitions"),
		RunsDir:              filepath.Join(base, "runs"),
		DefinitionCollection: bead.NewStoreWithCollection(beadRoot, execDefinitionCollection),
		RunCollection:        bead.NewStoreWithCollection(beadRoot, execRunCollection),
	}
}

func (s *Store) ListDefinitions(artifactID string) ([]Definition, error) {
	defs, _, err := s.loadDefinitions()
	if err != nil {
		return nil, err
	}
	if artifactID == "" {
		return defs, nil
	}
	filtered := make([]Definition, 0, len(defs))
	for _, def := range defs {
		if containsString(def.ArtifactIDs, artifactID) {
			filtered = append(filtered, def)
		}
	}
	return filtered, nil
}

func findDefinitionByID(defs []Definition, definitionID string) (Definition, error) {
	var (
		best  Definition
		found bool
	)
	for _, def := range defs {
		if def.ID != definitionID {
			continue
		}
		if !found || def.CreatedAt.After(best.CreatedAt) || (def.CreatedAt.Equal(best.CreatedAt) && def.ID > best.ID) {
			best = def
			found = true
		}
	}
	if !found {
		return Definition{}, fmt.Errorf("exec definition for %q not found", definitionID)
	}
	if best.ID == "" {
		return Definition{}, fmt.Errorf("exec definition for %q is missing id", definitionID)
	}
	return best, nil
}

func (s *Store) ShowDefinition(definitionID string) (Definition, error) {
	defs, _, err := s.loadDefinitions()
	if err != nil {
		return Definition{}, err
	}
	return findDefinitionByID(defs, definitionID)
}

func (s *Store) Validate(definitionID string) (*Definition, *docgraph.Document, error) {
	defs, graph, err := s.loadDefinitions()
	if err != nil {
		return nil, nil, err
	}
	def, err := findDefinitionByID(defs, definitionID)
	if err != nil {
		return nil, nil, err
	}
	if def.ID == "" {
		return nil, nil, fmt.Errorf("exec definition is missing id")
	}
	if len(def.ArtifactIDs) == 0 {
		return nil, nil, fmt.Errorf("exec definition %q has no artifact_ids", def.ID)
	}
	if def.Executor.Kind != ExecutorKindCommand && def.Executor.Kind != ExecutorKindAgent {
		return nil, nil, fmt.Errorf("exec definition %q has invalid executor kind %q", def.ID, def.Executor.Kind)
	}
	if def.Executor.Kind == ExecutorKindCommand && len(def.Executor.Command) == 0 {
		return nil, nil, fmt.Errorf("exec definition %q has no command", def.ID)
	}
	if graph == nil {
		graph, err = s.buildGraph()
		if err != nil {
			return nil, nil, err
		}
	}
	var primary *docgraph.Document
	for _, artifactID := range def.ArtifactIDs {
		doc, ok := graph.Show(artifactID)
		if !ok {
			return nil, nil, fmt.Errorf("exec definition %q references missing artifact %q", def.ID, artifactID)
		}
		if primary == nil {
			docCopy := doc
			primary = &docCopy
		}
	}
	return &def, primary, nil
}

func (s *Store) Run(ctx context.Context, definitionID string) (RunRecord, error) {
	return s.RunWithOptions(ctx, definitionID, RunOptions{})
}

func (s *Store) RunWithOptions(ctx context.Context, definitionID string, opts RunOptions) (RunRecord, error) {
	def, doc, err := s.Validate(definitionID)
	if err != nil {
		return RunRecord{}, err
	}
	if def.Executor.Kind == ExecutorKindAgent {
		if s.AgentRunner == nil {
			return RunRecord{}, fmt.Errorf("agent runner not configured for exec definition %q", def.ID)
		}

		var promptFile, promptText string
		if len(def.Executor.Command) > 0 {
			promptFile = def.Executor.Command[0]
		} else {
			promptText = def.Executor.Env["DDX_AGENT_PROMPT"]
		}

		workDir := def.Executor.Cwd
		if workDir == "" {
			workDir = s.WorkingDir
		} else if !filepath.IsAbs(workDir) {
			workDir = filepath.Join(s.WorkingDir, workDir)
		}

		overrides := config.CLIOverrides{
			Harness: def.Executor.Env["DDX_AGENT_HARNESS"],
			Model:   def.Executor.Env["DDX_AGENT_MODEL"],
			Effort:  def.Executor.Env["DDX_AGENT_EFFORT"],
		}
		if def.Executor.TimeoutMS > 0 {
			timeout := time.Duration(def.Executor.TimeoutMS) * time.Millisecond
			overrides.Timeout = &timeout
		}
		rcfg, _ := config.LoadAndResolve(s.WorkingDir, overrides)

		sessionID := genAgentSessionID()
		runtime := agent.AgentRunRuntime{
			Prompt:     promptText,
			PromptFile: promptFile,
			Correlation: map[string]string{
				"definition_id":     def.ID,
				"artifact_ids":      strings.Join(def.ArtifactIDs, ","),
				"produces_artifact": opts.ProducesArtifact,
				"session_id":        sessionID,
			},
			WorkDir: workDir,
		}

		start := time.Now().UTC()
		agentResult, agentErr := s.AgentRunner.Run(ctx, rcfg, runtime)
		finished := time.Now().UTC()

		status := StatusSuccess
		exitCode := 0
		var stdout, stderr string
		if agentErr != nil {
			status = StatusErrored
			exitCode = 1
			stderr = agentErr.Error()
		} else {
			exitCode = agentResult.ExitCode
			stdout = strings.TrimSpace(agentResult.Output)
			stderr = strings.TrimSpace(agentResult.Stderr)
			if exitCode != 0 {
				if exitCode == -1 && strings.Contains(agentResult.Error, "timeout") {
					status = StatusTimedOut
				} else {
					status = StatusFailed
				}
			}
		}

		runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
		record := RunRecord{
			RunManifest: RunManifest{
				RunID:            runID,
				DefinitionID:     def.ID,
				ArtifactIDs:      def.ArtifactIDs,
				ProducesArtifact: opts.ProducesArtifact,
				StartedAt:        start,
				FinishedAt:       finished,
				Status:           status,
				ExitCode:         exitCode,
				MergeBlocking:    def.Required && status != StatusSuccess,
				AgentSessionID:   sessionID,
				Attachments:      runAttachmentRefs(s.WorkingDir, runID),
				Provenance:       provenance(),
			},
			Result: RunResult{
				Stdout: stdout,
				Stderr: stderr,
			},
		}
		if saveErr := s.saveRunRecord(record); saveErr != nil {
			return RunRecord{}, saveErr
		}
		return record, nil
	}

	cwd := s.WorkingDir
	if def.Executor.Cwd != "" {
		if filepath.IsAbs(def.Executor.Cwd) {

		if filepath.IsAbs(def.Executor.Cwd) {
			cwd = def.Executor.Cwd
		} else {
			cwd = filepath.Join(s.WorkingDir, def.Executor.Cwd)
		}
	}

	cmd := osexec.CommandContext(ctx, def.Executor.Command[0], def.Executor.Command[1:]...)
	cmd.Dir = cwd
	if len(def.Executor.Env) > 0 {
		cmd.Env = append(os.Environ(), flattenEnv(def.Executor.Env)...)
	}

	start := time.Now().UTC()
	stdout, stderr, runErr := captureCommand(cmd)
	finished := time.Now().UTC()
	duration := finished.Sub(start)

	result := RunResult{
		Stdout: strings.TrimSpace(stdout),
		Stderr: strings.TrimSpace(stderr),
	}
	value, unit := normalizeMeasurement(stdout)
	if unit == "" && def.Result.Metric != nil {
		unit = def.Result.Metric.Unit
	}
	if unit != "" || value != 0 {
		result.Parsed = true
		result.Value = value
		result.Unit = unit
		result.Metric = &MetricObservation{
			ArtifactID:   doc.ID,
			DefinitionID: def.ID,
			ObservedAt:   start,
			Value:        value,
			Unit:         unit,
			Samples:      []float64{value},
		}
	}

	status := StatusSuccess
	exitCode := 0
	if runErr != nil {
		switch {
		case errors.Is(runErr, context.DeadlineExceeded):
			status = StatusTimedOut
		default:
			status = StatusFailed
		}
		var exitErr *osexec.ExitError
		if errors.As(runErr, &exitErr) {
			exitCode = exitErr.ExitCode()
		} else {
			exitCode = 1
		}
	}
	if result.Metric != nil {
		result.Metric.Status = metricStatusForRun(status)
		if status == StatusSuccess {
			result.Metric.Comparison = ComparisonResult{
				Baseline:  value,
				Delta:     0,
				Direction: def.Evaluation.Comparison,
			}
		}
	}

	runID := fmt.Sprintf("%s@%s-%d", def.ID, start.Format(time.RFC3339Nano), atomic.AddUint64(&s.runCounter, 1))
	record := RunRecord{
		RunManifest: RunManifest{
			RunID:            runID,
			DefinitionID:     def.ID,
			ArtifactIDs:      def.ArtifactIDs,
			ProducesArtifact: opts.ProducesArtifact,
			StartedAt:        start,
			FinishedAt:       finished,
			Status:           status,
			ExitCode:         exitCode,
			MergeBlocking:    def.Required && status != StatusSuccess,
			Attachments:      runAttachmentRefs(s.WorkingDir, runID),
			Provenance:       provenance(),
		},
		Result: result,
	}
	if writeErr := s.saveRunRecord(record); writeErr != nil {
		return RunRecord{}, writeErr
	}
	_ = duration
	return record, nil
}

func (s *Store) History(artifactID, definitionID string) ([]RunRecord, error) {
	entries, err := s.loadRuns()
	if err != nil {
		return nil, err
	}
	filtered := make([]RunRecord, 0, len(entries))
	for _, rec := range entries {
		if artifactID != "" && !containsString(rec.ArtifactIDs, artifactID) {
			continue
		}
		if definitionID != "" && rec.DefinitionID != definitionID {
			continue
		}
		filtered = append(filtered, rec)
	}
	return filtered, nil
}

func (s *Store) Log(runID string) (string, string, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return "", "", err
	}
	return rec.Result.Stdout, rec.Result.Stderr, nil
}

func (s *Store) Result(runID string) (RunResult, error) {
	rec, err := s.loadRunByID(runID)
	if err != nil {
		return RunResult{}, err
	}
	return rec.Result, nil
}

func (s *Store) SaveDefinition(def Definition) error {
	if def.ID == "" {
		return fmt.Errorf("id is required")
	}
	if len(def.ArtifactIDs) == 0 {
		return fmt.Errorf("artifact_ids is required")
	}
	return s.saveDefinitionBead(def)
}

func (s *Store) readRunBundle(dir string) (RunRecord, error) {
	manifestRaw, err := os.ReadFile(filepath.Join(dir, "manifest.json"))
	if err != nil {
		return RunRecord{}, err
	}
	resultRaw, err := os.ReadFile(filepath.Join(dir, "result.json"))
	if err != nil {
		return RunRecord{}, err
	}
	var manifest RunManifest
	if err := json.Unmarshal(manifestRaw, &manifest); err != nil {
		return RunRecord{}, err
	}
	var result RunResult
	if err := json.Unmarshal(resultRaw, &result); err != nil {
		return RunRecord{}, err
	}
	return RunRecord{RunManifest: manifest, Result: result}, nil
}

func syncPath(path string) error {
	f, err := os.Open(path)
	if err != nil {
		return err
	}
	defer f.Close()
	return f.Sync()
}

func provenance() Provenance {
	host, _ := os.Hostname()
	return Provenance{Host: host}
}

func containsString(values []string, target string) bool {
	for _, value := range values {
		if value == target {
			return true
		}
	}
	return false
}

func flattenEnv(values map[string]string) []string {
	out := make([]string, 0, len(values))
	for key, value := range values {
		out = append(out, fmt.Sprintf("%s=%s", key, value))
	}
	sort.Strings(out)
	return out
}

func captureCommand(cmd *osexec.Cmd) (string, string, error) {
	var stdoutBuf, stderrBuf strings.Builder
	cmd.Stdout = &stdoutBuf
	cmd.Stderr = &stderrBuf
	err := cmd.Run()
	return stdoutBuf.String(), stderrBuf.String(), err
}

var measurementPattern = regexp.MustCompile(`(?i)(-?\d+(?:\.\d+)?)(?:\s*)(ms|s|sec|seconds?)?`)

func normalizeMeasurement(stdout string) (float64, string) {
	trimmed := strings.TrimSpace(stdout)
	if trimmed == "" {
		return 0, ""
	}
	if value, unit, ok := parseJSONMeasurement(trimmed); ok {
		return value, unit
	}
	if value, unit, ok := parseTextMeasurement(trimmed); ok {
		return value, unit
	}
	return 0, ""
}

func parseJSONMeasurement(text string) (float64, string, bool) {
	var obj map[string]any
	if err := json.Unmarshal([]byte(text), &obj); err != nil {
		return 0, "", false
	}
	if raw, ok := obj["value"]; ok {
		switch v := raw.(type) {
		case float64:
			unit, _ := obj["unit"].(string)
			return v, unit, true
		case string:
			if parsed, err := strconv.ParseFloat(v, 64); err == nil {
				unit, _ := obj["unit"].(string)
				return parsed, unit, true
			}
		}
	}
	return 0, "", false
}

func parseTextMeasurement(text string) (float64, string, bool) {
	match := measurementPattern.FindStringSubmatch(text)
	if len(match) < 2 {
		return 0, "", false
	}
	value, err := strconv.ParseFloat(match[1], 64)
	if err != nil {
		return 0, "", false
	}
	unit := ""
	if len(match) >= 3 {
		unit = strings.ToLower(match[2])
	}
	return value, unit, true
}

func metricStatusForRun(status string) string {
	if status == StatusSuccess {
		return "pass"
	}
	return "fail"
}

func genAgentSessionID() string {
	b := make([]byte, 4)
	_, _ = rand.Read(b)
	return "as-" + hex.EncodeToString(b)
}

package exec

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/docgraph"
	"github.com/DocumentDrivenDX/ddx/internal/evidence"
)

// execPromptCapBytes caps the size of inline prompt env-var values
// (DDX_AGENT_PROMPT) carried by exec definitions. FEAT-022 §9 / Stage D2.
// Package-level variable so tests can lower the cap; production callers
// must not mutate it.
var execPromptCapBytes = evidence.DefaultMaxPromptBytes

// loadDefinitions returns all definitions and the doc graph built during loading.
// The graph may be nil if graph loading failed (soft error treated as empty).
func (s *Store) loadDefinitions() ([]Definition, *docgraph.Graph, error) {
	defs := make(map[string]Definition)

	// Graph-authored definitions take precedence over runtime-managed ones.
	// The graph is returned so callers can reuse it without a second build.
	graph, graphDefs, _ := s.loadGraphDefinitions()
	for _, def := range graphDefs {
		if def.ID == "" || !def.Active {
			continue
		}
		defs[def.ID] = def
	}

	if s.DefinitionCollection != nil {
		beads, err := s.DefinitionCollection.ReadAll()
		if err != nil {
			return nil, nil, err
		}
		for _, entry := range beads {
			def, err := definitionFromBead(entry)
			if err != nil {
				return nil, nil, err
			}
			if def.ID == "" || !def.Active {
				continue
			}
			if _, ok := defs[def.ID]; ok {
				continue // graph-authored takes precedence
			}
			defs[def.ID] = def
		}
	}

	legacy, err := s.readLegacyDefinitions()
	if err != nil {
		return nil, nil, err
	}
	for _, def := range legacy {
		if def.ID == "" || !def.Active {
			continue
		}
		if _, ok := defs[def.ID]; ok {
			continue
		}
		defs[def.ID] = def
	}

	out := make([]Definition, 0, len(defs))
	for _, def := range defs {
		if prompt, ok := def.Executor.Env["DDX_AGENT_PROMPT"]; ok {
			if observed := len([]byte(prompt)); observed > execPromptCapBytes {
				return nil, nil, fmt.Errorf(
					"exec definition %q env DDX_AGENT_PROMPT exceeds cap: observed %d bytes, cap %d bytes (configurable via .ddx/config.yaml:evidence_caps.max_prompt_bytes)",
					def.ID, observed, execPromptCapBytes)
			}
		}
		out = append(out, def)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].CreatedAt.Equal(out[j].CreatedAt) {
			return out[i].ID < out[j].ID
		}
		return out[i].CreatedAt.After(out[j].CreatedAt)
	})
	return out, graph, nil
}

// loadGraphDefinitions builds the doc graph and extracts exec definitions
// embedded in document frontmatter via the exec: block.
// Returns the built graph so callers can reuse it without a second walk.
func (s *Store) loadGraphDefinitions() (*docgraph.Graph, []Definition, error) {
	graph, err := s.buildGraph()
	if err != nil {
		return nil, nil, err
	}
	var defs []Definition
	for _, doc := range graph.Documents {
		if doc.ExecDef == nil {
			continue
		}
		ed := doc.ExecDef
		// ArtifactIDs: prefer the explicit list; fall back to the document's depends_on.
		artifactIDs := append([]string{}, ed.ArtifactIDs...)
		if len(artifactIDs) == 0 {
			artifactIDs = append(artifactIDs, doc.DependsOn...)
		}
		def := Definition{
			ID:          doc.ID,
			ArtifactIDs: artifactIDs,
			Executor: ExecutorSpec{
				Kind:      ed.Kind,
				Command:   ed.Command,
				Cwd:       ed.Cwd,
				Env:       ed.Env,
				TimeoutMS: ed.TimeoutMS,
			},
			Required:    ed.Required,
			Active:      ed.Active,
			GraphSource: true,
		}
		if ed.Comparison != "" || ed.Thresholds != nil {
			def.Evaluation = Evaluation{Comparison: ed.Comparison}
			if ed.Thresholds != nil {
				def.Evaluation.Thresholds = Thresholds{
					WarnMS:    ed.Thresholds.Warn,
					RatchetMS: ed.Thresholds.Ratchet,
				}
			}
		}
		if ed.Metric != nil {
			def.Result.Metric = &MetricResultSpec{
				Unit: ed.Metric.Unit,
			}
		}
		defs = append(defs, def)
	}
	return graph, defs, nil
}

func (s *Store) readLegacyDefinitions() ([]Definition, error) {
	entries, err := os.ReadDir(s.DefinitionsDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}

	defs := make([]Definition, 0, len(entries))
	for _, entry := range entries {
		if entry.IsDir() || !strings.HasSuffix(strings.ToLower(entry.Name()), ".json") {
			continue
		}
		raw, err := os.ReadFile(filepath.Join(s.DefinitionsDir, entry.Name()))
		if err != nil {
			return nil, err
		}
		var def Definition
		if err := json.Unmarshal(raw, &def); err != nil {
			return nil, fmt.Errorf("parse exec definition %q: %w", entry.Name(), err)
		}
		defs = append(defs, def)
	}
	return defs, nil
}

func (s *Store) loadRuns() ([]RunRecord, error) {
	runs := make(map[string]RunRecord)

	if s.RunCollection != nil {
		beads, err := s.RunCollection.ReadAll()
		if err != nil {
			return nil, err
		}
		for _, entry := range beads {
			rec, err := s.runRecordFromBead(entry)
			if err != nil {
				return nil, err
			}
			if rec.RunID == "" {
				continue
			}
			runs[rec.RunID] = rec
		}
	}

	legacy, err := s.readLegacyRuns()
	if err != nil {
		return nil, err
	}
	for _, rec := range legacy {
		if rec.RunID == "" {
			continue
		}
		if _, ok := runs[rec.RunID]; ok {
			continue
		}
		runs[rec.RunID] = rec
	}

	out := make([]RunRecord, 0, len(runs))
	for _, rec := range runs {
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		if out[i].StartedAt.Equal(out[j].StartedAt) {
			return out[i].RunID < out[j].RunID
		}
		return out[i].StartedAt.Before(out[j].StartedAt)
	})
	return out, nil
}

func (s *Store) readLegacyRuns() ([]RunRecord, error) {
	entries, err := os.ReadDir(s.RunsDir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}

	records := make([]RunRecord, 0, len(entries))
	for _, entry := range entries {
		if !entry.IsDir() || strings.HasPrefix(entry.Name(), ".tmp-") {
			continue
		}
		rec, err := s.readRunBundle(filepath.Join(s.RunsDir, entry.Name()))
		if err != nil {
			return nil, err
		}
		records = append(records, rec)
	}
	return records, nil
}

